-- ============================================
-- Update exercise content from reviewed CSV
-- ============================================

UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Ganzkörper"}', equipment = '{"Bodyweight"}', howto = 'Aufrechter Stand, Füße zusammen. Sprung: Beine schulterbreit öffnen, Arme über Kopf klatschen. Zurück in Ausgangsposition. 30–45 s rhythmisch. Atmung: fließend durch die Nase.' WHERE name = 'Jumping Jacks';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Schultern","Trapez"}', equipment = '{"Bodyweight"}', howto = 'Aufrechter Stand, Arme seitlich auf Schulterhöhe. Kleine Kreise vorwärts (10×), dann rückwärts (10×). Schultern dabei aktiv nach unten ziehen – nicht hochziehen.' WHERE name = 'Arm Circles';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Hüftbeuger","Quadrizeps","Waden","Core"}', equipment = '{"Bodyweight"}', howto = 'Auf der Stelle laufen, Knie abwechselnd auf Hüfthöhe ziehen. Oberkörper aufrecht, Arme aktiv mitschwingen. 30–45 s zügig. Gleichmäßige Atmung durch die Nase.' WHERE name = 'High Knees';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Hüfte","Hüftbeuger","Hamstrings"}', equipment = '{"Bodyweight"}', howto = 'An Wand abstützen, Standbein leicht gebeugt. Pendelbein locker vor und zurück schwingen – Schwung aus der Hüfte, nicht reißen. 10× je Seite vorwärts/rückwärts, dann 10× seitlich. Kein Hohlkreuz.' WHERE name = 'Leg Swings';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Schultern","Trapez","Rotatorenmanschette"}', equipment = '{"Bodyweight"}', howto = 'Aufrechter Stand, Arme hängen locker. Schultern langsam nach vorne–oben–hinten–unten kreisen (10×), dann umgekehrt (10×). Bewusst die Schulterblätter einbeziehen.' WHERE name = 'Schulterkreisen';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Schultern","Brust","Rücken"}', equipment = '{"Bodyweight"}', howto = 'Aufrechter Stand, Arme seitlich gestreckt. Arme nach vorne überkreuzen (Hugging Motion), dann weit nach hinten öffnen. 15× locker und dynamisch. Kein Anhalten an den Endpositionen.' WHERE name = 'Arm Swings';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Rücken","Core","Hüfte"}', equipment = '{"Bodyweight"}', howto = 'Vierfüßlerstand, Handgelenke unter Schultern, Knie unter Hüften. Einatmen → Brust absenken, Becken kippen (Cow). Ausatmen → Rücken rund machen, Nabel zur Wirbelsäule (Cat). 8–10 Wdh, langsam und kontrolliert.' WHERE name = 'Cat-Cow Stretch';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Waden","Ganzkörper","Cardio"}', equipment = '{"Springseil"}', howto = 'Leicht auf Fußballen federn, Knie minimal gebeugt. Seil knapp über dem Boden. Ellbogen nah am Körper, Handgelenke drehen das Seil. 30–60 s lockeres Tempo, Puls auf 120–130 bpm.' WHERE name = 'Seilspringen';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Cardio","Beine","Rücken"}', equipment = '{"Maschine"}', howto = 'Lockeres Tempo, Puls auf 120–130 bpm. Laufband: Steigung 2–3 %. Rudern: Beine → Rücken → Arme (Zugphase), Arme → Rücken → Beine (Rückführung). 5–10 min.' WHERE name = 'Laufband / Ruderergometer';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Schultern","Rotatorenmanschette","Brust"}', equipment = '{"Band"}', howto = 'Widerstandsband mit weitem Griff. Arme gestreckt: Band von vor dem Körper über den Kopf und hinter den Rücken führen. 10× vorwärts, 10× rückwärts. Bei Schmerz Griff verbreitern.' WHERE name = 'Schulterkreisen mit Band';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Rücken","Schultern","Core"}', equipment = '{"Bodyweight"}', howto = 'Cat-Cow (8–10 Wdh): Vierfüßlerstand, Einatmen → Brust senken, Ausatmen → Rücken rund. Thoracic Rotation: Hand hinter Kopf, Ellbogen zum Boden, dann weit zur Decke öffnen. 6× je Seite. Unterer Rücken bleibt neutral.' WHERE name = 'Cat-Cow + Thoracic Rotation';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Ganzkörper","Brust","Hamstrings","Core"}', equipment = '{"Bodyweight"}', howto = 'Aus dem Stand Hände zum Boden, in Liegestützposition laufen. 1 Push-Up. Zurück zu den Füßen laufen, aufrichten. 6–8 Wdh. Core während des gesamten Weges angespannt.' WHERE name = 'Inchworms + Push-Up';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Hüfte","Quadrizeps","Gesäß"}', equipment = '{"Kurzhantel"}', howto = 'Leichte KH (8–12 kg) beidhändig vor der Brust. Tiefe Kniebeuge: Ellbogen drücken Knie nach außen, Fersen am Boden. 20–30 s halten, 3×. Brust aufrecht, Blick geradeaus.' WHERE name = 'Goblet Squat Hold';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Unterarme"}', equipment = '{"Bodyweight"}', howto = 'Arm strecken, Handgelenk flektieren (Finger nach unten), andere Hand leicht Druck geben. 15 s halten. Dann Handgelenk extendieren (Finger nach oben), 15 s. 2× je Seite. Danach 5× Handgelenke kreisen.' WHERE name = 'Wrist Stretches';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Schultern","Rotatorenmanschette","Brust"}', equipment = '{"Band"}', howto = 'Band mit weitem Griff, Arme gestreckt vor dem Körper. Arme über Kopf und hinter den Rücken führen – Band bleibt gespannt. 10–12 Wdh. ⚠ Bei Schmerz sofort stoppen und Griff verbreitern.' WHERE name = 'Band Dislocates';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Rücken","Schultern","Unterarme"}', equipment = '{"Bodyweight"}', howto = 'Passiv (30 s): Entspannt hängen, Schultern lassen sich hochziehen. Aktiv (30 s): Schulterblätter nach unten ziehen ohne Arme zu beugen – Körper hebt sich leicht. Abwechseln. Entlastet die Wirbelsäule.' WHERE name = 'Hängen am Klimmzuggriff';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Rücken"}', equipment = '{"Schaumrolle"}', howto = 'Rolle quer unter die Schulterblätter, Hände hinter dem Kopf. Langsam von Mitte-Rücken bis oberen Rücken rollen. An steifen Stellen 10–15 s verweilen. ⚠ Nicht über die Lendenwirbelsäule rollen.' WHERE name = 'Thoracic Foam Roll';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Gesäß","Abduktoren","Quadrizeps"}', equipment = '{"Band"}', howto = 'Mini-Band über die Knie. Viertelhocke einnehmen, Knie aktiv nach außen drücken. 10 Schritte seitlich rechts, 10 links. Oberkörper aufrecht, kein Wippen.' WHERE name = 'Banded Crab Walks';
UPDATE exercise_library SET category = 'warmup', muscle_groups = '{"Core","Hüftbeuger","Schultern"}', equipment = '{"Bodyweight"}', howto = 'Rückenlage, Arme senkrecht zur Decke, Hüfte und Knie je 90°. Gegengleich: rechten Arm + linkes Bein langsam Richtung Boden strecken, unterer Rücken bleibt am Boden. Zurück. 6× je Seite. Ausatmen beim Strecken.' WHERE name = 'Dead Bug (Aktivierung)';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Brust","Trizeps","Vordere Schulter","Core"}', equipment = '{"Bodyweight"}', howto = 'Hände etwas breiter als Schultern, Körper gerade von Kopf bis Fersen. Ellbogen 45° zum Körper. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Hochdrücken. Regression: Knie aufsetzen.' WHERE name = 'Liegestütze klassisch';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Trizeps","Brust (innen)","Vordere Schulter"}', equipment = '{"Bodyweight"}', howto = 'Hände unter der Brust, Zeige- und Daumen bilden eine Raute. Körper gerade, Ellbogen nah am Körper. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Hochdrücken. Regression: Knie aufsetzen.' WHERE name = 'Liegestütze eng (Diamond)';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Schultern","Trizeps","Obere Brust"}', equipment = '{"Bodyweight"}', howto = 'Umgekehrtes V: Hüfte hoch, Kopf zwischen den Armen, Hände schulterbreit. Kopf kontrolliert Richtung Boden senken, dann drücken. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Hochdrücken.' WHERE name = 'Pike Push-Ups';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Brust (oberer)","Trizeps","Vordere Schulter"}', equipment = '{"Bodyweight"}', howto = 'Füße auf erhöhter Fläche, Hände am Boden. Körper gerade, Ellbogen 45° zum Körper. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Hochdrücken. Betont obere Brust stärker als flache Variante.' WHERE name = 'Decline Push-Ups';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Trizeps","Brust","Vordere Schulter"}', equipment = '{"Bodyweight"}', howto = 'Hände auf Stuhlkante hinter dem Körper, Finger nach vorne. Ellbogen bis 90° beugen – nicht tiefer. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Hochdrücken. Beine gestreckt = schwieriger.' WHERE name = 'Dips (Stuhl / Bank)';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Brust","Trizeps","Vordere Schulter"}', equipment = '{"Kurzhantel","Bank"}', howto = 'Flachbank, je eine KH. Schulterblätter zusammendrücken und in die Bank drücken. Oberarme 45° zum Körper. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Drücken. ⚠ Stopp bei Schmerz im vorderen Schultergelenk.' WHERE name = 'KH-Bankdrücken';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Schultern","Trizeps","Trapez (oberer)"}', equipment = '{"Kurzhantel"}', howto = 'Sitzend oder stehend, KH auf Schulterhöhe, Handflächen nach vorne. Arme über Kopf drücken bis fast gestreckt. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Drücken. Core angespannt, kein Hohlkreuz.' WHERE name = 'KH-Schulterdrücken';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Rücken","Bizeps","Hintere Schulter","Rhomboiden"}', equipment = '{"Bodyweight"}', howto = 'Unter einer Stange (Tisch, TRX) hängen, Körper gerade wie ein Brett. Brust zur Stange ziehen, Schulterblätter zusammenführen. Tempo: 2 s hoch, 1 s halten, 2 s runter. Ausatmen beim Ziehen. Regression: Knie beugen.' WHERE name = 'Bodyweight Rows (Australian Pull-Up)';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Rücken","Hintere Schulter","Rhomboiden"}', equipment = '{"Bodyweight"}', howto = 'Bauchlage, Arme gestreckt neben dem Körper, Handflächen nach unten. Arme über den Kopf führen (Snow-Angel-Bewegung), Schulterblätter aktiv zusammenziehen. Brust leicht vom Boden. 10–12 Wdh, 2 s pro Phase.' WHERE name = 'Reverse Snow Angels';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Rücken (Erector spinae)","Gesäß","Hintere Schulter"}', equipment = '{"Bodyweight"}', howto = 'Bauchlage, Arme nach vorne gestreckt. Arme, Brust und Beine gleichzeitig heben. 3 s halten, dann absenken. 10–12 Wdh. Ausatmen beim Heben. Langsam und kontrolliert – kein Rucken.' WHERE name = 'Superman Hold';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Rücken","Bizeps","Rhomboiden"}', equipment = '{"Bodyweight"}', howto = 'Türrahmen greifen, leicht zurücklehnen (Arme gestreckt). Oberkörper zur Tür ziehen, Schulterblätter aktiv zusammenführen. Tempo: 2 s hoch, 1 s halten, 2 s runter. Ausatmen beim Ziehen. Füße nah an Tür = schwieriger.' WHERE name = 'Türziehen';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Rücken","Bizeps","Hintere Schulter","Rhomboiden","Core"}', equipment = '{"Bodyweight"}', howto = 'Schulterbreiter Obergriff. Schulterblätter zuerst nach unten ziehen (Scapular Pull), dann Arme beugen – Kinn über die Stange. Tempo: 2 s hoch, 1 s halten, 3 s runter. Ausatmen beim Ziehen. Regression: Band-Assisted. ⚠ Stopp bei Schmerz im Ellbogen oder Schulter.' WHERE name = 'Klimmzüge';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Rücken","Bizeps","Brachialis","Rhomboiden"}', equipment = '{"Bodyweight"}', howto = 'Parallelgriff (Handflächen zueinander). Schulterblätter nach unten, dann Arme beugen bis Kinn über Griff. Tempo: 2 s hoch, 1 s halten, 3 s runter. Gelenksschonender als Obergriff. Ausatmen beim Ziehen.' WHERE name = 'Klimmzüge (Neutralgriff)';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Rücken","Bizeps","Hintere Schulter"}', equipment = '{"Band"}', howto = 'Widerstandsband über Stange, Knie oder Fuß ins Band. Schulterblätter nach unten, dann Arme beugen bis Kinn über Stange. Tempo: 2 s hoch, 3 s runter. Band gibt am unteren Totpunkt maximale Unterstützung. Ausatmen beim Ziehen.' WHERE name = 'Band-Assisted Pull-Up';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Bizeps","Brachialis","Unterarme"}', equipment = '{"Kurzhantel"}', howto = 'KH seitlich hängen, Handflächen nach vorne. Beim Hochführen Handgelenk leicht nach außen drehen. Oberarm fixiert am Körper. Tempo: 1 s hoch, 1 s Squeeze, 2 s runter. Ausatmen beim Curlen. Kein Schwung aus der Schulter.' WHERE name = 'Bizeps Curls';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Bizeps","Brachialis","Unterarme"}', equipment = '{"Kurzhantel"}', howto = 'KH seitlich, Handflächen zueinander – Griff bleibt neutral während der gesamten Bewegung. Oberarm fixiert. Tempo: 1 s hoch, 1 s halten, 2 s runter. Betont Brachialis stärker als klassischer Curl.' WHERE name = 'Hammer Curls';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Hintere Schulter","Rhomboiden","Rotatorenmanschette"}', equipment = '{"Band"}', howto = 'Band mit gestreckten Armen auf Brusthöhe. Arme seitlich auseinanderziehen bis Band die Brust berührt. 1 s halten, kontrolliert zurück. 15–20 Wdh. Schulterblätter aktiv zusammenführen. Ausatmen beim Auseinanderziehen.' WHERE name = 'Band Pull-Aparts';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Schultern (lateral)","Trapez (oberer)","Supraspinatus"}', equipment = '{"Maschine"}', howto = 'Seitlich zum Kabelzug, unterer Anschlag. Arm mit leichter Ellbogenbeugung bis Schulterhöhe heben. Tempo: 2 s hoch, 1 s halten, 2 s runter. Kein Schwung. Ausatmen beim Heben. ⚠ Nicht über Schulterhöhe – Impingement-Risiko.' WHERE name = 'Kabelzug Seitheben';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Trizeps","Brust","Vordere Schulter"}', equipment = '{"Maschine"}', howto = 'Oberkörper leicht vorbeugen für mehr Brustanteil (aufrecht = mehr Trizeps). Bis Oberarme parallel absenken. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Hochdrücken. ⚠ Stopp bei Schmerz im vorderen Schultergelenk.' WHERE name = 'Dips (Gerät)';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Trizeps","Unterarme"}', equipment = '{"Maschine"}', howto = 'Oberer Kabelzug, Seil oder Stange. Oberarme fixiert am Körper. Unterarme runterdrücken – beim Seil Enden am unteren Totpunkt auseinanderziehen. Tempo: 1 s runter, 1 s halten, 2 s zurück. Ausatmen beim Drücken.' WHERE name = 'Trizeps Pushdown';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Rücken","Bizeps","Hintere Schulter","Rhomboiden"}', equipment = '{"Maschine"}', howto = 'Schulterbreiter Griff. Schulterblätter zuerst nach unten, dann Arme beugen – Stange zur oberen Brust. Leicht zurücklehnen (10–15°). Tempo: 2 s runter, 1 s halten, 2 s zurück. Ausatmen beim Ziehen.' WHERE name = 'Lat Pulldown';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Hintere Schulter","Rhomboiden","Rotatorenmanschette"}', equipment = '{"Maschine"}', howto = 'Seil auf Gesichtshöhe. Zum Gesicht ziehen, Enden auseinander – Hände neben Ohren, Ellbogen hoch. 2 s halten. Tempo: 1 s ziehen, 2 s zurück. Ausatmen beim Ziehen.' WHERE name = 'Kabelzug Face Pulls';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Hintere Schulter","Rhomboiden","Trapez (mittlerer)"}', equipment = '{"Maschine"}', howto = 'Zwei Kabel von unten, Griffe über Kreuz. Vorgebeugt (45°), Arme seitlich nach oben/hinten führen. Schulterblätter am oberen Totpunkt zusammendrücken. Tempo: 2 s hoch, 1 s halten, 2 s runter.' WHERE name = 'Reverse Fly Kabelzug';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Rotatorenmanschette","Hintere Schulter"}', equipment = '{"Band"}', howto = 'Ellbogen 90° gebeugt, am Körper fixiert (Tuch zwischen Arm und Rumpf klemmen). Band innen fassen. Unterarm nach außen rotieren – nur der Unterarm bewegt sich. Tempo: 2 s außen, 1 s halten, 2 s zurück. 12–15 Wdh. ⚠ Keine Schleuderbewegung.' WHERE name = 'External Rotation (Band)';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Rotatorenmanschette","Hintere Schulter","Rhomboiden","Trapez"}', equipment = '{"Bodyweight"}', howto = 'Bauchlage. Y: Arme 45° über Kopf, Daumen zur Decke. T: Arme seitlich auf 90°. W: Ellbogen beugen, Hände auf Schulterhöhe. Jede Position 2 s halten, Schulterblätter aktiv zusammenziehen. Leichte KH (1–2 kg) optional.' WHERE name = 'Prone Y-T-W';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Rücken","Bizeps","Hintere Schulter","Rhomboiden"}', equipment = '{"Kurzhantel","Bank"}', howto = 'Knie und gleichseitige Hand auf Bank. KH zum Hüftknochen ziehen, Ellbogen eng. Schulterblatt am oberen Totpunkt zusammenziehen, 1 s halten. Tempo: 1 s hoch, 1 s halten, 2 s runter. Ausatmen beim Ziehen.' WHERE name = 'KH Rudern einarmig';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Rücken","Bizeps","Hintere Schulter","Rhomboiden"}', equipment = '{"Langhantel"}', howto = 'Schulterbreiter Obergriff, 45° vorgebeugt, Rücken neutral. Stange zum unteren Brustbein ziehen, Ellbogen hinter dem Körper. Kein Schwung. Tempo: 1 s hoch, 1 s halten, 2 s runter. Ausatmen beim Ziehen.' WHERE name = 'LH Bent-Over Row';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Quadrizeps","Gesäß","Hamstrings","Core"}', equipment = '{"Langhantel"}', howto = 'Stange auf Trapezius. Schulterbreiter Stand, Fußspitzen leicht nach außen. Core anspannen, Brust hoch, mindestens parallel. Explosiv aufstehen, Knie in Fußrichtung. Ausatmen beim Aufstehen. ⚠ Knie nicht nach innen fallen lassen.' WHERE name = 'LH Back Squat';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Quadrizeps","Gesäß","Hamstrings","Core"}', equipment = '{"Bodyweight"}', howto = 'Schulterbreiter Stand, Fußspitzen leicht nach außen. Hüfte nach hinten/unten – parallel oder tiefer. Knie in Fußrichtung, Fersen am Boden. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Aufstehen.' WHERE name = 'Kniebeugen';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Quadrizeps","Gesäß","Hamstrings","Core"}', equipment = '{"Bodyweight"}', howto = 'Großer Schritt nach vorne, hinteres Knie bis kurz über den Boden senken. Oberkörper aufrecht, vorderes Knie bleibt über dem Fuß. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Aufstehen.' WHERE name = 'Ausfallschritte';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Quadrizeps","Gesäß","Hamstrings","Core"}', equipment = '{"Kurzhantel"}', howto = 'KH seitlich hängen. Großer Schritt nach vorne, hinteres Knie bis kurz über den Boden. Oberkörper aufrecht, kein Vorbeugen. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Aufstehen. Progression zu Bodyweight-Ausfallschritt.' WHERE name = 'Ausfallschritte mit KH';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Quadrizeps","Gesäß","Hamstrings","Core"}', equipment = '{"Bodyweight","Bank"}', howto = 'Hinterer Fuß auf Bank. Vorderer Fuß weit genug vorne, dass Knie beim Absenken nicht über Fußspitze geht. Hüfte gerade nach unten senken. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Aufstehen. ⚠ Knie nicht nach innen.' WHERE name = 'Bulgarian Split Squats';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Gesäß","Hamstrings","Core"}', equipment = '{"Bodyweight"}', howto = 'Rückenlage, Füße hüftbreit, Knie 90°. Hüfte bis zur geraden Linie Knie–Hüfte–Schulter heben. 2 s anspannen. Tempo: 1 s hoch, 2 s halten, 2 s runter. Ausatmen beim Heben. Kein Hohlkreuz.' WHERE name = 'Glute Bridge';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Gesäß","Hamstrings","Core"}', equipment = '{"Bodyweight"}', howto = 'Wie Glute Bridge, ein Bein gestreckt in der Luft. Becken horizontal halten – nicht abkippen. Tempo: 2 s hoch, 1 s halten, 2 s runter. 10× je Seite. Ausatmen beim Heben. ⚠ Standbein-Knie bleibt stabil.' WHERE name = 'Single Leg Glute Bridge';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Quadrizeps","Gesäß","Hamstrings"}', equipment = '{"Bodyweight"}', howto = 'Rücken an Wand, Knie und Hüfte je 90°, Füße schulterbreit. Rücken komplett an der Wand – kein Hohlkreuz. 30–60 s halten. Gleichmäßige Atmung. Progression: einbeinig oder KH auf Oberschenkeln.' WHERE name = 'Wall Sit';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Adduktoren","Quadrizeps","Gesäß"}', equipment = '{"Bodyweight"}', howto = 'Breiter Stand (ca. 1,5× Schulterbreite), Fußspitzen ca. 45° nach außen. Knie in Fußrichtung beim Absenken. Rücken aufrecht. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Aufstehen.' WHERE name = 'Sumo Squats';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Waden (Gastrocnemius)","Soleus","Tibialis posterior"}', equipment = '{"Bodyweight"}', howto = 'Fußballen auf Kante, Fersen hängen. 2 s hoch, 1 s halten, 3 s runter – Fersen unter Kantenniveau für vollen Stretch. Einbeinig = deutlich schwieriger. Ausatmen beim Heben.' WHERE name = 'Calf Raises';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Hamstrings","Gesäß","Core","Waden"}', equipment = '{"Bodyweight","Kurzhantel"}', howto = 'Standbein leicht gebeugt. Oberkörper und Spielbein bilden eine Linie und kippen gleichzeitig nach vorne/hinten. Rücken neutral, Becken nicht rotieren. Tempo: 2 s runter, 1 s hoch. 10× je Seite.' WHERE name = 'Single Leg Deadlift';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Hamstrings","Gesäß","Unterer Rücken","Core"}', equipment = '{"Kurzhantel"}', howto = 'KH vor den Oberschenkeln, schulterbreiter Stand. Hüfte nach hinten schicken, Oberkörper neigt sich – Rücken bleibt neutral (kein runder Rücken!). Bis leichte Dehnung in Hamstrings, dann Hüfte nach vorne. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Aufstehen.' WHERE name = 'Rumänisches Kreuzheben';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Hamstrings","Waden (Gastrocnemius)"}', equipment = '{"Maschine"}', howto = 'Volle ROM: ganz strecken, ganz beugen. 1 s Squeeze am oberen Totpunkt, 3 s exzentrisch zurück. Hüften bleiben auf der Sitzfläche. Ausatmen beim Beugen.' WHERE name = 'Beinbeuger Maschine';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Waden (Gastrocnemius)","Soleus"}', equipment = '{"Maschine","Bodyweight"}', howto = 'Fußballen auf Kante. 2 s hoch, 1 s halten, 3 s runter, Fersen unter Niveau für Stretch. Schultern locker. Ausatmen beim Heben.' WHERE name = 'Wadenheben stehend';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Quadrizeps","Gesäß","Hamstrings","Core"}', equipment = '{"Bodyweight"}', howto = 'Fuß vollständig auf Stuhl/Box stellen. Mit Ferse hochdrücken – nicht mit hinterem Bein abstoßen. Oberkörper aufrecht. Tempo: 2 s hoch, 2 s runter. 10× je Seite. Ausatmen beim Hochdrücken. ⚠ Knie nicht nach innen.' WHERE name = 'Step-Up';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Quadrizeps","Gesäß","Hamstrings","Core"}', equipment = '{"Bodyweight"}', howto = 'Ein Bein gestreckt nach vorne, mit einer Hand an Wand/TRX abstützen. Auf Standbein tief in die Kniebeuge. Knie in Fußrichtung, Oberkörper leicht vor. Tempo: 3 s runter, 1 s hoch. Ausatmen beim Aufstehen.' WHERE name = 'Pistol Squat (Assisted)';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Beine","Gesäß","Waden","Core"}', equipment = '{"Bodyweight"}', howto = 'Aus der Kniebeuge explosiv abspringen – maximale Streckung. Weiche Landung: Fußballen zuerst, dann Ferse, sofort in nächste Kniebeuge abfedern. Ausatmen beim Abspringen. ⚠ Keine harte Fersenlandung.' WHERE name = 'Jump Squats';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Hamstrings","Gesäß","Core","Unterer Rücken","Schultern"}', equipment = '{"Kettlebell"}', howto = 'KB zwischen Beinen, hüftbreiter Stand. Rücken neutral, KB nach hinten (Hip Hinge – kein Squat!). Explosiver Hip Snap nach vorne – Arme passiv, Kraft aus Hüfte. KB bis Brusthöhe. Ausatmen am oberen Totpunkt. ⚠ Kein runder Rücken.' WHERE name = 'Kettlebell Swing';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Quadrizeps","Gesäß","Schultern","Trizeps","Core"}', equipment = '{"Kurzhantel"}', howto = 'KH auf Schulterhöhe. Tiefe Kniebeuge, dann explosiv aufstehen und KH direkt über Kopf drücken – eine fließende Bewegung ohne Stopp. Ausatmen beim Drücken über Kopf.' WHERE name = 'KH Thruster';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Brust","Rücken","Trizeps","Core"}', equipment = '{"Kurzhantel"}', howto = 'Auf zwei KH: Push-Up ausführen, dann KH abwechselnd zur Hüfte ziehen. Füße breit für Stabilität. Core verhindert seitliches Rotieren. Ausatmen beim Drücken und beim Ziehen.' WHERE name = 'Push-Up → Renegade Row';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Gesäß (Abduktoren)","Hüfte","Core"}', equipment = '{"Band"}', howto = 'Seitenlage, Knie 45° gebeugt, Füße übereinander. Oberes Knie wie eine Muschel öffnen – Füße bleiben zusammen. 2 s öffnen, 1 s halten, 2 s zurück. 12–15× je Seite. Becken darf nicht kippen. Mini-Band für mehr Widerstand.' WHERE name = 'Clamshells';
UPDATE exercise_library SET category = 'strength', muscle_groups = '{"Adduktoren","Core","Gesäß"}', equipment = '{"Bodyweight"}', howto = 'Seitstütz, oberes Bein liegt auf Bank (Innenknie auf Kante). Hüfte heben, Körper gerade. 20–30 s halten oder 10× Hüfte heben/senken. Ausatmen beim Halten. Progression: unteres Bein vom Boden heben.' WHERE name = 'Copenhagen Plank';
UPDATE exercise_library SET category = 'core', muscle_groups = '{"Core (Rectus abdominis)","Schultern","Gesäß","Hüftbeuger"}', equipment = '{"Bodyweight"}', howto = 'Unterarmstütz. Körper bildet gerade Linie: Kopf, Schultern, Hüfte, Fersen auf einer Höhe. Nabel zur Wirbelsäule, Gesäß nicht hochstrecken oder durchhängen. 20–60 s halten. Gleichmäßige Atmung.' WHERE name = 'Plank';
UPDATE exercise_library SET category = 'core', muscle_groups = '{"Core (Hüftbeuger)","Schultern","Quadrizeps"}', equipment = '{"Bodyweight"}', howto = 'Liegestützposition, Hände unter Schultern. Knie abwechselnd explosiv zur Brust ziehen – Hüfte bleibt unten, nicht pumpen. Ausatmen bei jedem Knieheben. 30 s zügig.' WHERE name = 'Mountain Climbers';
UPDATE exercise_library SET category = 'core', muscle_groups = '{"Core (Obliques)","Rectus abdominis","Hüftbeuger"}', equipment = '{"Bodyweight"}', howto = 'Rückenlage, Hände locker hinter Kopf, Knie 90°. Gegengleich: rechter Ellbogen zum linken Knie, linkes Bein streckt aus. Rotation aus dem Rumpf – nicht am Kopf ziehen. Tempo: kontrolliert, 2 s pro Seite.' WHERE name = 'Bicycle Crunches';
UPDATE exercise_library SET category = 'core', muscle_groups = '{"Core (Obliques)","Hüftbeuger","Rectus abdominis"}', equipment = '{"Bodyweight","Kurzhantel"}', howto = 'Sitzend, Oberkörper ca. 45° rückwärts geneigt, Beine leicht gebeugt. Hände oder KH beidhändig, Rumpf nach links und rechts rotieren. Rotation aus der Taille – nicht aus den Armen. Tempo: kontrolliert.' WHERE name = 'Russian Twists';
UPDATE exercise_library SET category = 'core', muscle_groups = '{"Core (Hüftbeuger)","Rectus abdominis"}', equipment = '{"Bodyweight"}', howto = 'Rückenlage, Hände unter Gesäß. Beine gestreckt zur Decke heben, dann kontrolliert absenken – nicht ganz auf den Boden. Unterer Rücken bleibt am Boden. Tempo: 2 s hoch, 2 s runter. Ausatmen beim Heben.' WHERE name = 'Leg Raises';
UPDATE exercise_library SET category = 'core', muscle_groups = '{"Core","Hüftbeuger","Schultern"}', equipment = '{"Bodyweight"}', howto = 'Rückenlage, Arme senkrecht zur Decke, Hüfte und Knie je 90°. Gegengleich: Arm + gegenüberliegendes Bein langsam strecken. Unterer Rücken fest am Boden. 10× je Seite. Ausatmen beim Strecken.' WHERE name = 'Dead Bug';
UPDATE exercise_library SET category = 'core', muscle_groups = '{"Core (Obliques)","Schultern","Gesäß (Abduktoren)"}', equipment = '{"Bodyweight"}', howto = 'Seitstütz auf Unterarm oder Hand. Hüfte hoch – kein Durchhängen. Freie Hand zur Decke. 20–40 s je Seite. Regression: Knie aufsetzen. Progression: 15× Hüfte heben/senken. Gleichmäßige Atmung.' WHERE name = 'Side Plank';
UPDATE exercise_library SET category = 'core', muscle_groups = '{"Core (Rectus abdominis)","Hüftbeuger","Schultern"}', equipment = '{"Bodyweight"}', howto = 'Rückenlage, Arme über Kopf gestreckt. Schultern und Beine gleichzeitig leicht vom Boden heben – nur unterer Rücken bleibt am Boden. 20–40 s halten. ⚠ Kein Hohlkreuz – wenn nötig, Beine höher nehmen.' WHERE name = 'Hollow Body Hold';
UPDATE exercise_library SET category = 'core', muscle_groups = '{"Core (Anti-Rotation)","Schultern","Hüftbeuger"}', equipment = '{"Maschine"}', howto = 'Kabelzug auf Brusthöhe, seitlich stehen. Griff beidhändig vor der Brust. Arme strecken (2 s halten), zurück. Rumpf widersteht der Rotation – keine Ausweichbewegung. 8–10 Wdh je Seite. Ausatmen beim Strecken.' WHERE name = 'Pallof Press';
UPDATE exercise_library SET category = 'core', muscle_groups = '{"Core","Schultern","Hüftbeuger"}', equipment = '{"Band"}', howto = 'Füße in TRX-Schlaufen, Unterarmstütz. Körper langsam nach vorne schieben, zurück. Kleine, kontrollierte Bewegung – maximale Rumpfspannung. 8–10 Wdh. Ausatmen beim Vorschieben.' WHERE name = 'TRX Body Saw';
UPDATE exercise_library SET category = 'core', muscle_groups = '{"Core (Obliques)","Schultern","Hüftbeuger"}', equipment = '{"Maschine"}', howto = 'Seitlich zum Kabelzug, Griff beidhändig. Diagonale Rotation von oben-außen nach unten-innen. Kraft aus der Rumpfrotation – nicht aus den Armen. Standbeine stabil. 8–10× je Seite. Ausatmen beim Rotieren.' WHERE name = 'Kabelzug Holzhacker';
UPDATE exercise_library SET category = 'cardio', muscle_groups = '{"Ganzkörper","Core","Brust","Beine"}', equipment = '{"Bodyweight"}', howto = 'Stand → Hände zum Boden → Beine nach hinten springen (Liegestützposition) → optional Push-Up → Beine zurückspringen → explosiv aufspringen mit Armheben. Weiche Landung. Ausatmen beim Aufspringen. 30–45 s.' WHERE name = 'Burpees';
UPDATE exercise_library SET category = 'cardio', muscle_groups = '{"Beine","Gesäß","Core","Waden"}', equipment = '{"Box"}', howto = 'Hüftbreiter Stand vor der Box. Armschwung für Impuls, explosiv aufspringen. Weiche Landung in Kniebeuge auf der Box. Kontrolliert heruntersteigen. Ausatmen beim Abspringen. ⚠ Nicht herunterspringen – Verletzungsrisiko Achillessehne.' WHERE name = 'Box Jumps';
UPDATE exercise_library SET category = 'cardio', muscle_groups = '{"Beine","Gesäß","Core","Adduktoren"}', equipment = '{"Bodyweight"}', howto = 'Auf einem Bein abfedern, seitlich zum anderen Bein springen. Auf einem Fuß landen, kurz stabilisieren. Kurze Aufsetzzeit, Arme als Gegengewicht. 30 s rhythmisch. Ausatmen beim Abspringen.' WHERE name = 'Skater Jumps';
UPDATE exercise_library SET category = 'cardio', muscle_groups = '{"Ganzkörper","Core","Schultern","Hüftbeuger"}', equipment = '{"Bodyweight"}', howto = 'Vierfüßlerstand, Knie 2 cm über dem Boden. Diagonal vorwärts: rechte Hand + linkes Knie gleichzeitig. Rücken flach, Hüfte tief. 10 m vorwärts, 10 m rückwärts. Gleichmäßige Atmung.' WHERE name = 'Bear Crawl';
UPDATE exercise_library SET category = 'cardio', muscle_groups = '{"Beine","Core","Hüftbeuger"}', equipment = '{"Bodyweight"}', howto = 'Aus dem Stand explosiv abspringen, Knie zur Brust ziehen (Tuck-Position). Weiche Landung auf Fußballen, sofort abfedern. 30 s. Ausatmen beim Abspringen. ⚠ Keine Fersenlandung.' WHERE name = 'Tuck Jumps';
UPDATE exercise_library SET category = 'cardio', muscle_groups = '{"Beine (lateral)","Gesäß (Abduktoren)","Core"}', equipment = '{"Bodyweight"}', howto = 'Leichte Kniebeuge (Athletic Stance). Seitliche Schritte in Gruppen von 3–4, kurzer Bodenkontakt. Oberkörper aufrecht, Hüfte tief. 30 s. Ausatmen rhythmisch.' WHERE name = 'Lateral Shuffles';
UPDATE exercise_library SET category = 'stretch', muscle_groups = '{"Hüfte","Piriformis","Gesäß"}', equipment = '{"Bodyweight"}', howto = 'Aus dem Vierfüßlerstand: Vorderes Knie nach vorne, Unterschenkel quer zur Matte. Hinteres Bein gestreckt. Oberkörper aufrichten oder auf Unterarmen abstützen. 30–60 s je Seite. Tief in die Dehnung atmen, bei jedem Ausatmen entspannen.' WHERE name = 'Pigeon Pose';
UPDATE exercise_library SET category = 'stretch', muscle_groups = '{"Hamstrings"}', equipment = '{"Bodyweight"}', howto = 'Stehend: ein Bein auf erhöhter Fläche (Hüfthöhe), Knie leicht gebeugt. Oberkörper gerade nach vorne – nicht runden. 30 s je Seite. Alternativ liegend mit Band um Fuß. Tiefe Atmung, kein Schwingen.' WHERE name = 'Hamstring Stretch';
UPDATE exercise_library SET category = 'stretch', muscle_groups = '{"Hüfte","Piriformis","Adduktoren","Außenrotatoren"}', equipment = '{"Bodyweight"}', howto = 'Sitzend: vorderes und hinteres Bein je 90° gebeugt. Oberkörper aufrecht. Über das vordere Bein nach vorne neigen für intensivere Dehnung. 30 s je Seite, dann Beine wechseln. Tief atmen.' WHERE name = 'Hip 90/90 Stretch';
UPDATE exercise_library SET category = 'stretch', muscle_groups = '{"Schultern","Brust","Rotatorenmanschette"}', equipment = '{"Band"}', howto = 'Band mit weitem Griff über Kopf rotieren und hinter Rücken führen, Arme gestreckt halten. Bei engem Schultergürtel Griff verbreitern. 10–12 Wdh. ⚠ Schmerz = sofort stoppen.' WHERE name = 'Shoulder Dislocates';
UPDATE exercise_library SET category = 'stretch', muscle_groups = '{"Ganzkörper","Hüfte","Brustwirbelsäule","Schultern"}', equipment = '{"Bodyweight"}', howto = 'Ausfallschritt. Gleichseitige Hand innen neben Fuß auf Boden. Gegenläufiger Arm zur Decke rotieren. Dann Hüfte strecken (Hip Flexor Dehnung). 5 Atemzüge je Seite. Langsam und kontrolliert.' WHERE name = 'World''s Greatest Stretch';
UPDATE exercise_library SET category = 'stretch', muscle_groups = '{"Waden","Achillessehne","Tibialis anterior"}', equipment = '{"Bodyweight"}', howto = 'Fuß 10 cm von der Wand. Knie zur Wand führen – Ferse bleibt am Boden. 10× je Seite. Danach Fußkreisen (je 10×). Wichtig vor Kniebeugen und Ausfallschritten.' WHERE name = 'Sprunggelenk-Mobilisation';
UPDATE exercise_library SET category = 'stretch', muscle_groups = '{"Quadrizeps"}', equipment = '{"Bodyweight"}', howto = 'Stehend: Ferse zur Gesäßbacke ziehen, Knie zusammenhalten. Hand an Wand für Balance. Hüfte leicht nach vorne kippen für intensivere Hüftbeuger-Dehnung. 30 s je Seite.' WHERE name = 'Quadrizeps Stretch';
UPDATE exercise_library SET category = 'stretch', muscle_groups = '{"Brust","Vordere Schulter","Bizeps"}', equipment = '{"Bodyweight"}', howto = 'Unterarm senkrecht im Türrahmen (Ellbogen auf Schulterhöhe). Oberkörper vorsichtig durch den Rahmen drehen. 30 s je Seite. Beide Armpositionen (90° und über Kopf) für verschiedene Brustabschnitte.' WHERE name = 'Brustdehnung (Türrahmen)';
UPDATE exercise_library SET category = 'stretch', muscle_groups = '{"Trizeps","Schultern"}', equipment = '{"Bodyweight"}', howto = 'Arm über den Kopf, Ellbogen gebeugt (Hand zwischen Schulterblättern). Mit anderer Hand Ellbogen sanft nach hinten drücken. 30 s je Seite. Oberkörper aufrecht. Ausatmen beim Vertiefen.' WHERE name = 'Trizeps Stretch';
UPDATE exercise_library SET category = 'stretch', muscle_groups = '{"Rücken","Hüfte","Schultern"}', equipment = '{"Bodyweight"}', howto = 'Knieend: Hüfte auf Fersen senken, Arme nach vorne gestreckt, Stirn auf Matte. 30–60 s halten. Für Schulteranteil: Hände zur Seite wandern. Tiefe Bauchatmung. Entlastet die Lendenwirbelsäule.' WHERE name = 'Kindshaltung (Child''s Pose)';
UPDATE exercise_library SET category = 'stretch', muscle_groups = '{"Hals (seitliche Nackenmuskulatur)"}', equipment = '{"Bodyweight"}', howto = 'Ohr zur Schulter, Hand leicht auf Kopf für sanften Zug. 30 s je Seite. Gegenseitige Schulter aktiv nach unten drücken für intensivere Dehnung. Tiefe Atmung. ⚠ Niemals rucken.' WHERE name = 'Seitliche Nacken-Dehnung';
UPDATE exercise_library SET category = 'stretch', muscle_groups = '{"Hintere Schulter","Rhomboiden"}', equipment = '{"Bodyweight"}', howto = 'Arm auf Schulterhöhe gestreckt, mit gegenläufiger Hand Ellbogen zum Körper ziehen. 30 s je Seite. Schulter des gestreckten Arms aktiv nach unten drücken. Tief atmen.' WHERE name = 'Cross-Body Shoulder Stretch';
UPDATE exercise_library SET category = 'stretch', muscle_groups = '{"Schultern","Rotatorenmanschette","Brust","Trapez"}', equipment = '{"Bodyweight"}', howto = 'Rücken an Wand, Lendenwirbelsäule so nah wie möglich. Arme in W-Position (Ellbogen auf Schulterhöhe). Arme langsam über Kopf strecken (Y-Position) – Rücken und Arme bleiben an der Wand. 10 Wdh. ⚠ Kein Hohlkreuz.' WHERE name = 'Wall Angels';
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Jumping Jacks', 'warmup', '{"Ganzkörper"}', '{"Bodyweight"}', 'Aufrechter Stand, Füße zusammen. Sprung: Beine schulterbreit öffnen, Arme über Kopf klatschen. Zurück in Ausgangsposition. 30–45 s rhythmisch. Atmung: fließend durch die Nase.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Jumping Jacks');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Arm Circles', 'warmup', '{"Schultern","Trapez"}', '{"Bodyweight"}', 'Aufrechter Stand, Arme seitlich auf Schulterhöhe. Kleine Kreise vorwärts (10×), dann rückwärts (10×). Schultern dabei aktiv nach unten ziehen – nicht hochziehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Arm Circles');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'High Knees', 'warmup', '{"Hüftbeuger","Quadrizeps","Waden","Core"}', '{"Bodyweight"}', 'Auf der Stelle laufen, Knie abwechselnd auf Hüfthöhe ziehen. Oberkörper aufrecht, Arme aktiv mitschwingen. 30–45 s zügig. Gleichmäßige Atmung durch die Nase.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'High Knees');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Leg Swings', 'warmup', '{"Hüfte","Hüftbeuger","Hamstrings"}', '{"Bodyweight"}', 'An Wand abstützen, Standbein leicht gebeugt. Pendelbein locker vor und zurück schwingen – Schwung aus der Hüfte, nicht reißen. 10× je Seite vorwärts/rückwärts, dann 10× seitlich. Kein Hohlkreuz.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Leg Swings');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Schulterkreisen', 'warmup', '{"Schultern","Trapez","Rotatorenmanschette"}', '{"Bodyweight"}', 'Aufrechter Stand, Arme hängen locker. Schultern langsam nach vorne–oben–hinten–unten kreisen (10×), dann umgekehrt (10×). Bewusst die Schulterblätter einbeziehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Schulterkreisen');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Arm Swings', 'warmup', '{"Schultern","Brust","Rücken"}', '{"Bodyweight"}', 'Aufrechter Stand, Arme seitlich gestreckt. Arme nach vorne überkreuzen (Hugging Motion), dann weit nach hinten öffnen. 15× locker und dynamisch. Kein Anhalten an den Endpositionen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Arm Swings');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Cat-Cow Stretch', 'warmup', '{"Rücken","Core","Hüfte"}', '{"Bodyweight"}', 'Vierfüßlerstand, Handgelenke unter Schultern, Knie unter Hüften. Einatmen → Brust absenken, Becken kippen (Cow). Ausatmen → Rücken rund machen, Nabel zur Wirbelsäule (Cat). 8–10 Wdh, langsam und kontrolliert.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Cat-Cow Stretch');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Seilspringen', 'warmup', '{"Waden","Ganzkörper","Cardio"}', '{"Springseil"}', 'Leicht auf Fußballen federn, Knie minimal gebeugt. Seil knapp über dem Boden. Ellbogen nah am Körper, Handgelenke drehen das Seil. 30–60 s lockeres Tempo, Puls auf 120–130 bpm.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Seilspringen');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Laufband / Ruderergometer', 'warmup', '{"Cardio","Beine","Rücken"}', '{"Maschine"}', 'Lockeres Tempo, Puls auf 120–130 bpm. Laufband: Steigung 2–3 %. Rudern: Beine → Rücken → Arme (Zugphase), Arme → Rücken → Beine (Rückführung). 5–10 min.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Laufband / Ruderergometer');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Schulterkreisen mit Band', 'warmup', '{"Schultern","Rotatorenmanschette","Brust"}', '{"Band"}', 'Widerstandsband mit weitem Griff. Arme gestreckt: Band von vor dem Körper über den Kopf und hinter den Rücken führen. 10× vorwärts, 10× rückwärts. Bei Schmerz Griff verbreitern.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Schulterkreisen mit Band');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Cat-Cow + Thoracic Rotation', 'warmup', '{"Rücken","Schultern","Core"}', '{"Bodyweight"}', 'Cat-Cow (8–10 Wdh): Vierfüßlerstand, Einatmen → Brust senken, Ausatmen → Rücken rund. Thoracic Rotation: Hand hinter Kopf, Ellbogen zum Boden, dann weit zur Decke öffnen. 6× je Seite. Unterer Rücken bleibt neutral.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Cat-Cow + Thoracic Rotation');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Inchworms + Push-Up', 'warmup', '{"Ganzkörper","Brust","Hamstrings","Core"}', '{"Bodyweight"}', 'Aus dem Stand Hände zum Boden, in Liegestützposition laufen. 1 Push-Up. Zurück zu den Füßen laufen, aufrichten. 6–8 Wdh. Core während des gesamten Weges angespannt.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Inchworms + Push-Up');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Goblet Squat Hold', 'warmup', '{"Hüfte","Quadrizeps","Gesäß"}', '{"Kurzhantel"}', 'Leichte KH (8–12 kg) beidhändig vor der Brust. Tiefe Kniebeuge: Ellbogen drücken Knie nach außen, Fersen am Boden. 20–30 s halten, 3×. Brust aufrecht, Blick geradeaus.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Goblet Squat Hold');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Wrist Stretches', 'warmup', '{"Unterarme"}', '{"Bodyweight"}', 'Arm strecken, Handgelenk flektieren (Finger nach unten), andere Hand leicht Druck geben. 15 s halten. Dann Handgelenk extendieren (Finger nach oben), 15 s. 2× je Seite. Danach 5× Handgelenke kreisen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Wrist Stretches');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Band Dislocates', 'warmup', '{"Schultern","Rotatorenmanschette","Brust"}', '{"Band"}', 'Band mit weitem Griff, Arme gestreckt vor dem Körper. Arme über Kopf und hinter den Rücken führen – Band bleibt gespannt. 10–12 Wdh. ⚠ Bei Schmerz sofort stoppen und Griff verbreitern.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Band Dislocates');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Hängen am Klimmzuggriff', 'warmup', '{"Rücken","Schultern","Unterarme"}', '{"Bodyweight"}', 'Passiv (30 s): Entspannt hängen, Schultern lassen sich hochziehen. Aktiv (30 s): Schulterblätter nach unten ziehen ohne Arme zu beugen – Körper hebt sich leicht. Abwechseln. Entlastet die Wirbelsäule.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Hängen am Klimmzuggriff');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Thoracic Foam Roll', 'warmup', '{"Rücken"}', '{"Schaumrolle"}', 'Rolle quer unter die Schulterblätter, Hände hinter dem Kopf. Langsam von Mitte-Rücken bis oberen Rücken rollen. An steifen Stellen 10–15 s verweilen. ⚠ Nicht über die Lendenwirbelsäule rollen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Thoracic Foam Roll');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Banded Crab Walks', 'warmup', '{"Gesäß","Abduktoren","Quadrizeps"}', '{"Band"}', 'Mini-Band über die Knie. Viertelhocke einnehmen, Knie aktiv nach außen drücken. 10 Schritte seitlich rechts, 10 links. Oberkörper aufrecht, kein Wippen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Banded Crab Walks');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Dead Bug (Aktivierung)', 'warmup', '{"Core","Hüftbeuger","Schultern"}', '{"Bodyweight"}', 'Rückenlage, Arme senkrecht zur Decke, Hüfte und Knie je 90°. Gegengleich: rechten Arm + linkes Bein langsam Richtung Boden strecken, unterer Rücken bleibt am Boden. Zurück. 6× je Seite. Ausatmen beim Strecken.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Dead Bug (Aktivierung)');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Liegestütze klassisch', 'strength', '{"Brust","Trizeps","Vordere Schulter","Core"}', '{"Bodyweight"}', 'Hände etwas breiter als Schultern, Körper gerade von Kopf bis Fersen. Ellbogen 45° zum Körper. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Hochdrücken. Regression: Knie aufsetzen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Liegestütze klassisch');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Liegestütze eng (Diamond)', 'strength', '{"Trizeps","Brust (innen)","Vordere Schulter"}', '{"Bodyweight"}', 'Hände unter der Brust, Zeige- und Daumen bilden eine Raute. Körper gerade, Ellbogen nah am Körper. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Hochdrücken. Regression: Knie aufsetzen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Liegestütze eng (Diamond)');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Pike Push-Ups', 'strength', '{"Schultern","Trizeps","Obere Brust"}', '{"Bodyweight"}', 'Umgekehrtes V: Hüfte hoch, Kopf zwischen den Armen, Hände schulterbreit. Kopf kontrolliert Richtung Boden senken, dann drücken. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Hochdrücken.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Pike Push-Ups');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Decline Push-Ups', 'strength', '{"Brust (oberer)","Trizeps","Vordere Schulter"}', '{"Bodyweight"}', 'Füße auf erhöhter Fläche, Hände am Boden. Körper gerade, Ellbogen 45° zum Körper. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Hochdrücken. Betont obere Brust stärker als flache Variante.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Decline Push-Ups');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Dips (Stuhl / Bank)', 'strength', '{"Trizeps","Brust","Vordere Schulter"}', '{"Bodyweight"}', 'Hände auf Stuhlkante hinter dem Körper, Finger nach vorne. Ellbogen bis 90° beugen – nicht tiefer. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Hochdrücken. Beine gestreckt = schwieriger.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Dips (Stuhl / Bank)');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'KH-Bankdrücken', 'strength', '{"Brust","Trizeps","Vordere Schulter"}', '{"Kurzhantel","Bank"}', 'Flachbank, je eine KH. Schulterblätter zusammendrücken und in die Bank drücken. Oberarme 45° zum Körper. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Drücken. ⚠ Stopp bei Schmerz im vorderen Schultergelenk.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'KH-Bankdrücken');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'KH-Schulterdrücken', 'strength', '{"Schultern","Trizeps","Trapez (oberer)"}', '{"Kurzhantel"}', 'Sitzend oder stehend, KH auf Schulterhöhe, Handflächen nach vorne. Arme über Kopf drücken bis fast gestreckt. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Drücken. Core angespannt, kein Hohlkreuz.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'KH-Schulterdrücken');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Bodyweight Rows (Australian Pull-Up)', 'strength', '{"Rücken","Bizeps","Hintere Schulter","Rhomboiden"}', '{"Bodyweight"}', 'Unter einer Stange (Tisch, TRX) hängen, Körper gerade wie ein Brett. Brust zur Stange ziehen, Schulterblätter zusammenführen. Tempo: 2 s hoch, 1 s halten, 2 s runter. Ausatmen beim Ziehen. Regression: Knie beugen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Bodyweight Rows (Australian Pull-Up)');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Reverse Snow Angels', 'strength', '{"Rücken","Hintere Schulter","Rhomboiden"}', '{"Bodyweight"}', 'Bauchlage, Arme gestreckt neben dem Körper, Handflächen nach unten. Arme über den Kopf führen (Snow-Angel-Bewegung), Schulterblätter aktiv zusammenziehen. Brust leicht vom Boden. 10–12 Wdh, 2 s pro Phase.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Reverse Snow Angels');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Superman Hold', 'strength', '{"Rücken (Erector spinae)","Gesäß","Hintere Schulter"}', '{"Bodyweight"}', 'Bauchlage, Arme nach vorne gestreckt. Arme, Brust und Beine gleichzeitig heben. 3 s halten, dann absenken. 10–12 Wdh. Ausatmen beim Heben. Langsam und kontrolliert – kein Rucken.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Superman Hold');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Türziehen', 'strength', '{"Rücken","Bizeps","Rhomboiden"}', '{"Bodyweight"}', 'Türrahmen greifen, leicht zurücklehnen (Arme gestreckt). Oberkörper zur Tür ziehen, Schulterblätter aktiv zusammenführen. Tempo: 2 s hoch, 1 s halten, 2 s runter. Ausatmen beim Ziehen. Füße nah an Tür = schwieriger.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Türziehen');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Klimmzüge', 'strength', '{"Rücken","Bizeps","Hintere Schulter","Rhomboiden","Core"}', '{"Bodyweight"}', 'Schulterbreiter Obergriff. Schulterblätter zuerst nach unten ziehen (Scapular Pull), dann Arme beugen – Kinn über die Stange. Tempo: 2 s hoch, 1 s halten, 3 s runter. Ausatmen beim Ziehen. Regression: Band-Assisted. ⚠ Stopp bei Schmerz im Ellbogen oder Schulter.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Klimmzüge');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Klimmzüge (Neutralgriff)', 'strength', '{"Rücken","Bizeps","Brachialis","Rhomboiden"}', '{"Bodyweight"}', 'Parallelgriff (Handflächen zueinander). Schulterblätter nach unten, dann Arme beugen bis Kinn über Griff. Tempo: 2 s hoch, 1 s halten, 3 s runter. Gelenksschonender als Obergriff. Ausatmen beim Ziehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Klimmzüge (Neutralgriff)');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Band-Assisted Pull-Up', 'strength', '{"Rücken","Bizeps","Hintere Schulter"}', '{"Band"}', 'Widerstandsband über Stange, Knie oder Fuß ins Band. Schulterblätter nach unten, dann Arme beugen bis Kinn über Stange. Tempo: 2 s hoch, 3 s runter. Band gibt am unteren Totpunkt maximale Unterstützung. Ausatmen beim Ziehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Band-Assisted Pull-Up');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Bizeps Curls', 'strength', '{"Bizeps","Brachialis","Unterarme"}', '{"Kurzhantel"}', 'KH seitlich hängen, Handflächen nach vorne. Beim Hochführen Handgelenk leicht nach außen drehen. Oberarm fixiert am Körper. Tempo: 1 s hoch, 1 s Squeeze, 2 s runter. Ausatmen beim Curlen. Kein Schwung aus der Schulter.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Bizeps Curls');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Hammer Curls', 'strength', '{"Bizeps","Brachialis","Unterarme"}', '{"Kurzhantel"}', 'KH seitlich, Handflächen zueinander – Griff bleibt neutral während der gesamten Bewegung. Oberarm fixiert. Tempo: 1 s hoch, 1 s halten, 2 s runter. Betont Brachialis stärker als klassischer Curl.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Hammer Curls');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Band Pull-Aparts', 'strength', '{"Hintere Schulter","Rhomboiden","Rotatorenmanschette"}', '{"Band"}', 'Band mit gestreckten Armen auf Brusthöhe. Arme seitlich auseinanderziehen bis Band die Brust berührt. 1 s halten, kontrolliert zurück. 15–20 Wdh. Schulterblätter aktiv zusammenführen. Ausatmen beim Auseinanderziehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Band Pull-Aparts');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Kabelzug Seitheben', 'strength', '{"Schultern (lateral)","Trapez (oberer)","Supraspinatus"}', '{"Maschine"}', 'Seitlich zum Kabelzug, unterer Anschlag. Arm mit leichter Ellbogenbeugung bis Schulterhöhe heben. Tempo: 2 s hoch, 1 s halten, 2 s runter. Kein Schwung. Ausatmen beim Heben. ⚠ Nicht über Schulterhöhe – Impingement-Risiko.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Kabelzug Seitheben');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Dips (Gerät)', 'strength', '{"Trizeps","Brust","Vordere Schulter"}', '{"Maschine"}', 'Oberkörper leicht vorbeugen für mehr Brustanteil (aufrecht = mehr Trizeps). Bis Oberarme parallel absenken. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Hochdrücken. ⚠ Stopp bei Schmerz im vorderen Schultergelenk.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Dips (Gerät)');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Trizeps Pushdown', 'strength', '{"Trizeps","Unterarme"}', '{"Maschine"}', 'Oberer Kabelzug, Seil oder Stange. Oberarme fixiert am Körper. Unterarme runterdrücken – beim Seil Enden am unteren Totpunkt auseinanderziehen. Tempo: 1 s runter, 1 s halten, 2 s zurück. Ausatmen beim Drücken.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Trizeps Pushdown');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Lat Pulldown', 'strength', '{"Rücken","Bizeps","Hintere Schulter","Rhomboiden"}', '{"Maschine"}', 'Schulterbreiter Griff. Schulterblätter zuerst nach unten, dann Arme beugen – Stange zur oberen Brust. Leicht zurücklehnen (10–15°). Tempo: 2 s runter, 1 s halten, 2 s zurück. Ausatmen beim Ziehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Lat Pulldown');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Kabelzug Face Pulls', 'strength', '{"Hintere Schulter","Rhomboiden","Rotatorenmanschette"}', '{"Maschine"}', 'Seil auf Gesichtshöhe. Zum Gesicht ziehen, Enden auseinander – Hände neben Ohren, Ellbogen hoch. 2 s halten. Tempo: 1 s ziehen, 2 s zurück. Ausatmen beim Ziehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Kabelzug Face Pulls');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Reverse Fly Kabelzug', 'strength', '{"Hintere Schulter","Rhomboiden","Trapez (mittlerer)"}', '{"Maschine"}', 'Zwei Kabel von unten, Griffe über Kreuz. Vorgebeugt (45°), Arme seitlich nach oben/hinten führen. Schulterblätter am oberen Totpunkt zusammendrücken. Tempo: 2 s hoch, 1 s halten, 2 s runter.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Reverse Fly Kabelzug');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'External Rotation (Band)', 'strength', '{"Rotatorenmanschette","Hintere Schulter"}', '{"Band"}', 'Ellbogen 90° gebeugt, am Körper fixiert (Tuch zwischen Arm und Rumpf klemmen). Band innen fassen. Unterarm nach außen rotieren – nur der Unterarm bewegt sich. Tempo: 2 s außen, 1 s halten, 2 s zurück. 12–15 Wdh. ⚠ Keine Schleuderbewegung.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'External Rotation (Band)');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Prone Y-T-W', 'strength', '{"Rotatorenmanschette","Hintere Schulter","Rhomboiden","Trapez"}', '{"Bodyweight"}', 'Bauchlage. Y: Arme 45° über Kopf, Daumen zur Decke. T: Arme seitlich auf 90°. W: Ellbogen beugen, Hände auf Schulterhöhe. Jede Position 2 s halten, Schulterblätter aktiv zusammenziehen. Leichte KH (1–2 kg) optional.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Prone Y-T-W');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'KH Rudern einarmig', 'strength', '{"Rücken","Bizeps","Hintere Schulter","Rhomboiden"}', '{"Kurzhantel","Bank"}', 'Knie und gleichseitige Hand auf Bank. KH zum Hüftknochen ziehen, Ellbogen eng. Schulterblatt am oberen Totpunkt zusammenziehen, 1 s halten. Tempo: 1 s hoch, 1 s halten, 2 s runter. Ausatmen beim Ziehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'KH Rudern einarmig');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'LH Bent-Over Row', 'strength', '{"Rücken","Bizeps","Hintere Schulter","Rhomboiden"}', '{"Langhantel"}', 'Schulterbreiter Obergriff, 45° vorgebeugt, Rücken neutral. Stange zum unteren Brustbein ziehen, Ellbogen hinter dem Körper. Kein Schwung. Tempo: 1 s hoch, 1 s halten, 2 s runter. Ausatmen beim Ziehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'LH Bent-Over Row');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'LH Back Squat', 'strength', '{"Quadrizeps","Gesäß","Hamstrings","Core"}', '{"Langhantel"}', 'Stange auf Trapezius. Schulterbreiter Stand, Fußspitzen leicht nach außen. Core anspannen, Brust hoch, mindestens parallel. Explosiv aufstehen, Knie in Fußrichtung. Ausatmen beim Aufstehen. ⚠ Knie nicht nach innen fallen lassen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'LH Back Squat');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Kniebeugen', 'strength', '{"Quadrizeps","Gesäß","Hamstrings","Core"}', '{"Bodyweight"}', 'Schulterbreiter Stand, Fußspitzen leicht nach außen. Hüfte nach hinten/unten – parallel oder tiefer. Knie in Fußrichtung, Fersen am Boden. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Aufstehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Kniebeugen');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Ausfallschritte', 'strength', '{"Quadrizeps","Gesäß","Hamstrings","Core"}', '{"Bodyweight"}', 'Großer Schritt nach vorne, hinteres Knie bis kurz über den Boden senken. Oberkörper aufrecht, vorderes Knie bleibt über dem Fuß. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Aufstehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Ausfallschritte');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Ausfallschritte mit KH', 'strength', '{"Quadrizeps","Gesäß","Hamstrings","Core"}', '{"Kurzhantel"}', 'KH seitlich hängen. Großer Schritt nach vorne, hinteres Knie bis kurz über den Boden. Oberkörper aufrecht, kein Vorbeugen. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Aufstehen. Progression zu Bodyweight-Ausfallschritt.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Ausfallschritte mit KH');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Bulgarian Split Squats', 'strength', '{"Quadrizeps","Gesäß","Hamstrings","Core"}', '{"Bodyweight","Bank"}', 'Hinterer Fuß auf Bank. Vorderer Fuß weit genug vorne, dass Knie beim Absenken nicht über Fußspitze geht. Hüfte gerade nach unten senken. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Aufstehen. ⚠ Knie nicht nach innen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Bulgarian Split Squats');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Glute Bridge', 'strength', '{"Gesäß","Hamstrings","Core"}', '{"Bodyweight"}', 'Rückenlage, Füße hüftbreit, Knie 90°. Hüfte bis zur geraden Linie Knie–Hüfte–Schulter heben. 2 s anspannen. Tempo: 1 s hoch, 2 s halten, 2 s runter. Ausatmen beim Heben. Kein Hohlkreuz.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Glute Bridge');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Single Leg Glute Bridge', 'strength', '{"Gesäß","Hamstrings","Core"}', '{"Bodyweight"}', 'Wie Glute Bridge, ein Bein gestreckt in der Luft. Becken horizontal halten – nicht abkippen. Tempo: 2 s hoch, 1 s halten, 2 s runter. 10× je Seite. Ausatmen beim Heben. ⚠ Standbein-Knie bleibt stabil.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Single Leg Glute Bridge');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Wall Sit', 'strength', '{"Quadrizeps","Gesäß","Hamstrings"}', '{"Bodyweight"}', 'Rücken an Wand, Knie und Hüfte je 90°, Füße schulterbreit. Rücken komplett an der Wand – kein Hohlkreuz. 30–60 s halten. Gleichmäßige Atmung. Progression: einbeinig oder KH auf Oberschenkeln.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Wall Sit');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Sumo Squats', 'strength', '{"Adduktoren","Quadrizeps","Gesäß"}', '{"Bodyweight"}', 'Breiter Stand (ca. 1,5× Schulterbreite), Fußspitzen ca. 45° nach außen. Knie in Fußrichtung beim Absenken. Rücken aufrecht. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Aufstehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Sumo Squats');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Calf Raises', 'strength', '{"Waden (Gastrocnemius)","Soleus","Tibialis posterior"}', '{"Bodyweight"}', 'Fußballen auf Kante, Fersen hängen. 2 s hoch, 1 s halten, 3 s runter – Fersen unter Kantenniveau für vollen Stretch. Einbeinig = deutlich schwieriger. Ausatmen beim Heben.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Calf Raises');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Single Leg Deadlift', 'strength', '{"Hamstrings","Gesäß","Core","Waden"}', '{"Bodyweight","Kurzhantel"}', 'Standbein leicht gebeugt. Oberkörper und Spielbein bilden eine Linie und kippen gleichzeitig nach vorne/hinten. Rücken neutral, Becken nicht rotieren. Tempo: 2 s runter, 1 s hoch. 10× je Seite.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Single Leg Deadlift');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Rumänisches Kreuzheben', 'strength', '{"Hamstrings","Gesäß","Unterer Rücken","Core"}', '{"Kurzhantel"}', 'KH vor den Oberschenkeln, schulterbreiter Stand. Hüfte nach hinten schicken, Oberkörper neigt sich – Rücken bleibt neutral (kein runder Rücken!). Bis leichte Dehnung in Hamstrings, dann Hüfte nach vorne. Tempo: 2 s runter, 1 s hoch. Ausatmen beim Aufstehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Rumänisches Kreuzheben');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Beinbeuger Maschine', 'strength', '{"Hamstrings","Waden (Gastrocnemius)"}', '{"Maschine"}', 'Volle ROM: ganz strecken, ganz beugen. 1 s Squeeze am oberen Totpunkt, 3 s exzentrisch zurück. Hüften bleiben auf der Sitzfläche. Ausatmen beim Beugen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Beinbeuger Maschine');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Wadenheben stehend', 'strength', '{"Waden (Gastrocnemius)","Soleus"}', '{"Maschine","Bodyweight"}', 'Fußballen auf Kante. 2 s hoch, 1 s halten, 3 s runter, Fersen unter Niveau für Stretch. Schultern locker. Ausatmen beim Heben.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Wadenheben stehend');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Step-Up', 'strength', '{"Quadrizeps","Gesäß","Hamstrings","Core"}', '{"Bodyweight"}', 'Fuß vollständig auf Stuhl/Box stellen. Mit Ferse hochdrücken – nicht mit hinterem Bein abstoßen. Oberkörper aufrecht. Tempo: 2 s hoch, 2 s runter. 10× je Seite. Ausatmen beim Hochdrücken. ⚠ Knie nicht nach innen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Step-Up');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Pistol Squat (Assisted)', 'strength', '{"Quadrizeps","Gesäß","Hamstrings","Core"}', '{"Bodyweight"}', 'Ein Bein gestreckt nach vorne, mit einer Hand an Wand/TRX abstützen. Auf Standbein tief in die Kniebeuge. Knie in Fußrichtung, Oberkörper leicht vor. Tempo: 3 s runter, 1 s hoch. Ausatmen beim Aufstehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Pistol Squat (Assisted)');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Jump Squats', 'strength', '{"Beine","Gesäß","Waden","Core"}', '{"Bodyweight"}', 'Aus der Kniebeuge explosiv abspringen – maximale Streckung. Weiche Landung: Fußballen zuerst, dann Ferse, sofort in nächste Kniebeuge abfedern. Ausatmen beim Abspringen. ⚠ Keine harte Fersenlandung.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Jump Squats');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Kettlebell Swing', 'strength', '{"Hamstrings","Gesäß","Core","Unterer Rücken","Schultern"}', '{"Kettlebell"}', 'KB zwischen Beinen, hüftbreiter Stand. Rücken neutral, KB nach hinten (Hip Hinge – kein Squat!). Explosiver Hip Snap nach vorne – Arme passiv, Kraft aus Hüfte. KB bis Brusthöhe. Ausatmen am oberen Totpunkt. ⚠ Kein runder Rücken.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Kettlebell Swing');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'KH Thruster', 'strength', '{"Quadrizeps","Gesäß","Schultern","Trizeps","Core"}', '{"Kurzhantel"}', 'KH auf Schulterhöhe. Tiefe Kniebeuge, dann explosiv aufstehen und KH direkt über Kopf drücken – eine fließende Bewegung ohne Stopp. Ausatmen beim Drücken über Kopf.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'KH Thruster');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Push-Up → Renegade Row', 'strength', '{"Brust","Rücken","Trizeps","Core"}', '{"Kurzhantel"}', 'Auf zwei KH: Push-Up ausführen, dann KH abwechselnd zur Hüfte ziehen. Füße breit für Stabilität. Core verhindert seitliches Rotieren. Ausatmen beim Drücken und beim Ziehen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Push-Up → Renegade Row');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Clamshells', 'strength', '{"Gesäß (Abduktoren)","Hüfte","Core"}', '{"Band"}', 'Seitenlage, Knie 45° gebeugt, Füße übereinander. Oberes Knie wie eine Muschel öffnen – Füße bleiben zusammen. 2 s öffnen, 1 s halten, 2 s zurück. 12–15× je Seite. Becken darf nicht kippen. Mini-Band für mehr Widerstand.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Clamshells');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Copenhagen Plank', 'strength', '{"Adduktoren","Core","Gesäß"}', '{"Bodyweight"}', 'Seitstütz, oberes Bein liegt auf Bank (Innenknie auf Kante). Hüfte heben, Körper gerade. 20–30 s halten oder 10× Hüfte heben/senken. Ausatmen beim Halten. Progression: unteres Bein vom Boden heben.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Copenhagen Plank');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Plank', 'core', '{"Core (Rectus abdominis)","Schultern","Gesäß","Hüftbeuger"}', '{"Bodyweight"}', 'Unterarmstütz. Körper bildet gerade Linie: Kopf, Schultern, Hüfte, Fersen auf einer Höhe. Nabel zur Wirbelsäule, Gesäß nicht hochstrecken oder durchhängen. 20–60 s halten. Gleichmäßige Atmung.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Plank');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Mountain Climbers', 'core', '{"Core (Hüftbeuger)","Schultern","Quadrizeps"}', '{"Bodyweight"}', 'Liegestützposition, Hände unter Schultern. Knie abwechselnd explosiv zur Brust ziehen – Hüfte bleibt unten, nicht pumpen. Ausatmen bei jedem Knieheben. 30 s zügig.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Mountain Climbers');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Bicycle Crunches', 'core', '{"Core (Obliques)","Rectus abdominis","Hüftbeuger"}', '{"Bodyweight"}', 'Rückenlage, Hände locker hinter Kopf, Knie 90°. Gegengleich: rechter Ellbogen zum linken Knie, linkes Bein streckt aus. Rotation aus dem Rumpf – nicht am Kopf ziehen. Tempo: kontrolliert, 2 s pro Seite.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Bicycle Crunches');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Russian Twists', 'core', '{"Core (Obliques)","Hüftbeuger","Rectus abdominis"}', '{"Bodyweight","Kurzhantel"}', 'Sitzend, Oberkörper ca. 45° rückwärts geneigt, Beine leicht gebeugt. Hände oder KH beidhändig, Rumpf nach links und rechts rotieren. Rotation aus der Taille – nicht aus den Armen. Tempo: kontrolliert.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Russian Twists');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Leg Raises', 'core', '{"Core (Hüftbeuger)","Rectus abdominis"}', '{"Bodyweight"}', 'Rückenlage, Hände unter Gesäß. Beine gestreckt zur Decke heben, dann kontrolliert absenken – nicht ganz auf den Boden. Unterer Rücken bleibt am Boden. Tempo: 2 s hoch, 2 s runter. Ausatmen beim Heben.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Leg Raises');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Dead Bug', 'core', '{"Core","Hüftbeuger","Schultern"}', '{"Bodyweight"}', 'Rückenlage, Arme senkrecht zur Decke, Hüfte und Knie je 90°. Gegengleich: Arm + gegenüberliegendes Bein langsam strecken. Unterer Rücken fest am Boden. 10× je Seite. Ausatmen beim Strecken.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Dead Bug');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Side Plank', 'core', '{"Core (Obliques)","Schultern","Gesäß (Abduktoren)"}', '{"Bodyweight"}', 'Seitstütz auf Unterarm oder Hand. Hüfte hoch – kein Durchhängen. Freie Hand zur Decke. 20–40 s je Seite. Regression: Knie aufsetzen. Progression: 15× Hüfte heben/senken. Gleichmäßige Atmung.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Side Plank');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Hollow Body Hold', 'core', '{"Core (Rectus abdominis)","Hüftbeuger","Schultern"}', '{"Bodyweight"}', 'Rückenlage, Arme über Kopf gestreckt. Schultern und Beine gleichzeitig leicht vom Boden heben – nur unterer Rücken bleibt am Boden. 20–40 s halten. ⚠ Kein Hohlkreuz – wenn nötig, Beine höher nehmen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Hollow Body Hold');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Pallof Press', 'core', '{"Core (Anti-Rotation)","Schultern","Hüftbeuger"}', '{"Maschine"}', 'Kabelzug auf Brusthöhe, seitlich stehen. Griff beidhändig vor der Brust. Arme strecken (2 s halten), zurück. Rumpf widersteht der Rotation – keine Ausweichbewegung. 8–10 Wdh je Seite. Ausatmen beim Strecken.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Pallof Press');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'TRX Body Saw', 'core', '{"Core","Schultern","Hüftbeuger"}', '{"Band"}', 'Füße in TRX-Schlaufen, Unterarmstütz. Körper langsam nach vorne schieben, zurück. Kleine, kontrollierte Bewegung – maximale Rumpfspannung. 8–10 Wdh. Ausatmen beim Vorschieben.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'TRX Body Saw');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Kabelzug Holzhacker', 'core', '{"Core (Obliques)","Schultern","Hüftbeuger"}', '{"Maschine"}', 'Seitlich zum Kabelzug, Griff beidhändig. Diagonale Rotation von oben-außen nach unten-innen. Kraft aus der Rumpfrotation – nicht aus den Armen. Standbeine stabil. 8–10× je Seite. Ausatmen beim Rotieren.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Kabelzug Holzhacker');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Burpees', 'cardio', '{"Ganzkörper","Core","Brust","Beine"}', '{"Bodyweight"}', 'Stand → Hände zum Boden → Beine nach hinten springen (Liegestützposition) → optional Push-Up → Beine zurückspringen → explosiv aufspringen mit Armheben. Weiche Landung. Ausatmen beim Aufspringen. 30–45 s.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Burpees');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Box Jumps', 'cardio', '{"Beine","Gesäß","Core","Waden"}', '{"Box"}', 'Hüftbreiter Stand vor der Box. Armschwung für Impuls, explosiv aufspringen. Weiche Landung in Kniebeuge auf der Box. Kontrolliert heruntersteigen. Ausatmen beim Abspringen. ⚠ Nicht herunterspringen – Verletzungsrisiko Achillessehne.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Box Jumps');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Skater Jumps', 'cardio', '{"Beine","Gesäß","Core","Adduktoren"}', '{"Bodyweight"}', 'Auf einem Bein abfedern, seitlich zum anderen Bein springen. Auf einem Fuß landen, kurz stabilisieren. Kurze Aufsetzzeit, Arme als Gegengewicht. 30 s rhythmisch. Ausatmen beim Abspringen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Skater Jumps');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Bear Crawl', 'cardio', '{"Ganzkörper","Core","Schultern","Hüftbeuger"}', '{"Bodyweight"}', 'Vierfüßlerstand, Knie 2 cm über dem Boden. Diagonal vorwärts: rechte Hand + linkes Knie gleichzeitig. Rücken flach, Hüfte tief. 10 m vorwärts, 10 m rückwärts. Gleichmäßige Atmung.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Bear Crawl');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Tuck Jumps', 'cardio', '{"Beine","Core","Hüftbeuger"}', '{"Bodyweight"}', 'Aus dem Stand explosiv abspringen, Knie zur Brust ziehen (Tuck-Position). Weiche Landung auf Fußballen, sofort abfedern. 30 s. Ausatmen beim Abspringen. ⚠ Keine Fersenlandung.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Tuck Jumps');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Lateral Shuffles', 'cardio', '{"Beine (lateral)","Gesäß (Abduktoren)","Core"}', '{"Bodyweight"}', 'Leichte Kniebeuge (Athletic Stance). Seitliche Schritte in Gruppen von 3–4, kurzer Bodenkontakt. Oberkörper aufrecht, Hüfte tief. 30 s. Ausatmen rhythmisch.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Lateral Shuffles');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Pigeon Pose', 'stretch', '{"Hüfte","Piriformis","Gesäß"}', '{"Bodyweight"}', 'Aus dem Vierfüßlerstand: Vorderes Knie nach vorne, Unterschenkel quer zur Matte. Hinteres Bein gestreckt. Oberkörper aufrichten oder auf Unterarmen abstützen. 30–60 s je Seite. Tief in die Dehnung atmen, bei jedem Ausatmen entspannen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Pigeon Pose');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Hamstring Stretch', 'stretch', '{"Hamstrings"}', '{"Bodyweight"}', 'Stehend: ein Bein auf erhöhter Fläche (Hüfthöhe), Knie leicht gebeugt. Oberkörper gerade nach vorne – nicht runden. 30 s je Seite. Alternativ liegend mit Band um Fuß. Tiefe Atmung, kein Schwingen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Hamstring Stretch');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Hip 90/90 Stretch', 'stretch', '{"Hüfte","Piriformis","Adduktoren","Außenrotatoren"}', '{"Bodyweight"}', 'Sitzend: vorderes und hinteres Bein je 90° gebeugt. Oberkörper aufrecht. Über das vordere Bein nach vorne neigen für intensivere Dehnung. 30 s je Seite, dann Beine wechseln. Tief atmen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Hip 90/90 Stretch');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Shoulder Dislocates', 'stretch', '{"Schultern","Brust","Rotatorenmanschette"}', '{"Band"}', 'Band mit weitem Griff über Kopf rotieren und hinter Rücken führen, Arme gestreckt halten. Bei engem Schultergürtel Griff verbreitern. 10–12 Wdh. ⚠ Schmerz = sofort stoppen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Shoulder Dislocates');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'World''s Greatest Stretch', 'stretch', '{"Ganzkörper","Hüfte","Brustwirbelsäule","Schultern"}', '{"Bodyweight"}', 'Ausfallschritt. Gleichseitige Hand innen neben Fuß auf Boden. Gegenläufiger Arm zur Decke rotieren. Dann Hüfte strecken (Hip Flexor Dehnung). 5 Atemzüge je Seite. Langsam und kontrolliert.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'World''s Greatest Stretch');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Sprunggelenk-Mobilisation', 'stretch', '{"Waden","Achillessehne","Tibialis anterior"}', '{"Bodyweight"}', 'Fuß 10 cm von der Wand. Knie zur Wand führen – Ferse bleibt am Boden. 10× je Seite. Danach Fußkreisen (je 10×). Wichtig vor Kniebeugen und Ausfallschritten.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Sprunggelenk-Mobilisation');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Quadrizeps Stretch', 'stretch', '{"Quadrizeps"}', '{"Bodyweight"}', 'Stehend: Ferse zur Gesäßbacke ziehen, Knie zusammenhalten. Hand an Wand für Balance. Hüfte leicht nach vorne kippen für intensivere Hüftbeuger-Dehnung. 30 s je Seite.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Quadrizeps Stretch');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Brustdehnung (Türrahmen)', 'stretch', '{"Brust","Vordere Schulter","Bizeps"}', '{"Bodyweight"}', 'Unterarm senkrecht im Türrahmen (Ellbogen auf Schulterhöhe). Oberkörper vorsichtig durch den Rahmen drehen. 30 s je Seite. Beide Armpositionen (90° und über Kopf) für verschiedene Brustabschnitte.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Brustdehnung (Türrahmen)');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Trizeps Stretch', 'stretch', '{"Trizeps","Schultern"}', '{"Bodyweight"}', 'Arm über den Kopf, Ellbogen gebeugt (Hand zwischen Schulterblättern). Mit anderer Hand Ellbogen sanft nach hinten drücken. 30 s je Seite. Oberkörper aufrecht. Ausatmen beim Vertiefen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Trizeps Stretch');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Kindshaltung (Child''s Pose)', 'stretch', '{"Rücken","Hüfte","Schultern"}', '{"Bodyweight"}', 'Knieend: Hüfte auf Fersen senken, Arme nach vorne gestreckt, Stirn auf Matte. 30–60 s halten. Für Schulteranteil: Hände zur Seite wandern. Tiefe Bauchatmung. Entlastet die Lendenwirbelsäule.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Kindshaltung (Child''s Pose)');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Seitliche Nacken-Dehnung', 'stretch', '{"Hals (seitliche Nackenmuskulatur)"}', '{"Bodyweight"}', 'Ohr zur Schulter, Hand leicht auf Kopf für sanften Zug. 30 s je Seite. Gegenseitige Schulter aktiv nach unten drücken für intensivere Dehnung. Tiefe Atmung. ⚠ Niemals rucken.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Seitliche Nacken-Dehnung');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Cross-Body Shoulder Stretch', 'stretch', '{"Hintere Schulter","Rhomboiden"}', '{"Bodyweight"}', 'Arm auf Schulterhöhe gestreckt, mit gegenläufiger Hand Ellbogen zum Körper ziehen. 30 s je Seite. Schulter des gestreckten Arms aktiv nach unten drücken. Tief atmen.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Cross-Body Shoulder Stretch');
INSERT INTO exercise_library (name, category, muscle_groups, equipment, howto, is_public) SELECT 'Wall Angels', 'stretch', '{"Schultern","Rotatorenmanschette","Brust","Trapez"}', '{"Bodyweight"}', 'Rücken an Wand, Lendenwirbelsäule so nah wie möglich. Arme in W-Position (Ellbogen auf Schulterhöhe). Arme langsam über Kopf strecken (Y-Position) – Rücken und Arme bleiben an der Wand. 10 Wdh. ⚠ Kein Hohlkreuz.', true WHERE NOT EXISTS (SELECT 1 FROM exercise_library WHERE name = 'Wall Angels');
